    12→export function usePointsScreen(params?: PointsProps): UsePointsScreenReturn {
    13→  const hasFocused = useRef(false);
    14→  const modalizeRef = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
    15→  const [isMyOrders, setIsMyOrders] = useState(false);
    16→
    17→  const { products, status: productsStatus } = useRootStore((state) => state.pointsProducts);
    18→  const { points, status: balanceStatus } = useRootStore((state) => state.pointsBalance);
    19→  const { pointsProductsActions } = useRootStore.getState();
    20→  const { pointsExtractActions } = useRootStore.getState();
    21→
    22→  const isLoadingBalance = balanceStatus === PointsBalanceStatus.LOADING || balanceStatus === PointsBalanceStatus.IDLE;
    23→  const isLoadingProducts = productsStatus === PointsProductsStatus.LOADING || productsStatus === PointsProductsStatus.IDLE;
    24→  const isErrorBalance = balanceStatus === PointsBalanceStatus.ERROR;
    25→  const isErrorProducts = productsStatus === PointsProductsStatus.ERROR;
    26→
    27→  const buildPointsCardItems = useCardBuilderWhereUseMyPoints();
    28→
    29→  const handleGoBack = useCallback(() => {
    30→    params?.navigation?.goBack();
    31→  }, [params?.navigation]);
    32→
    33→  const handleOpenDefault = useCallback(() => {
    34→    eventSelectContent({
    35→      content_type: 'cta',
    36→      content_id: 'informacao_pontos',
    37→      location_1: 'monetizacao',
    38→      location_2: 'hub_recompensas_spmais',
    39→      location_3: 'home_hub_recompensas',
    40→    });
    41→    modalizeRef.current?.open?.();
    42→  }, []);
    43→
    44→  const handleOpenMyOrders = useCallback(() => {
    45→    setIsMyOrders(true);
    46→    eventModalView({
    47→      content_id: 'menu_header',
    48→      location_1: 'monetizacao',
    49→      location_2: 'hub_recompensas_spmais',
    50→      location_3: 'home_hub_recompensas',
    51→    });
    52→  }, []);
    53→
    54→  const requestPointsCallback = useCallback(() => {
    55→    getPointsBalance();
    56→    getPointsProducts();
    57→    getParameterPointsProgram();
    58→  }, []);
    59→
    60→  const handleApiErrorPress = useCallback(() => {
    61→    if (isErrorBalance || isErrorProducts) {
    62→      pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
    63→      pointsProductsActions.setStatus(PointsProductsStatus.IDLE);
    64→      requestPointsCallback();
    65→    }
