    67→
    68→  const handleOpenExtract = useCallback(() => {
    69→    eventSelectContent({
    70→      content_type: 'cta',
    71→      content_id: 'exibir_extrato',
    72→      location_1: 'monetizacao',
    73→      location_2: 'hub_recompensas_spmais',
    74→      location_3: 'home_hub_recompensas',
    75→    });
    76→    params?.navigation?.navigate('ExtractRewardProgram', {
    77→      analytics: {
    78→        screen_name: 'extrato_hub_recompensas',
    79→        screen_class: 'hub_recompensas_spmais',
    80→        screen_bussines: 'monetizacao',
    81→        screen_info: {
    82→          location_1: 'monetizacao',
    83→          location_2: 'hub_recompensas_spmais',
    84→          location_3: 'extrato_hub_recompensas',
    85→        },
    86→      },
    87→    });
    88→  }, [params?.navigation]);
    89→
    90→  useFocusEffect(
    91→    useCallback(() => {
    92→      if (!hasFocused.current) {
    93→        eventScreenViewV3('home_hub_recompensas', 'hub_recompensas_spmais', 'monetizacao', {
    94→          location_1: 'monetizacao',
    95→          location_2: 'hub_recompensas_spmais',
    96→          location_3: 'home_hub_recompensas',
    97→        });
    98→        hasFocused.current = true;
    99→      }
   100→      return () => {
   101→        hasFocused.current = false;
   102→      };
   103→    }, [])
